import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute } from '@angular/router';
import { AuthService } from '../../core/services/auth.service';
import { BudgetLine } from '../../core/models';

interface Pt { x: number; y: number; }
interface Seg { d: string; over: boolean; }
interface GridLine { y: number; label: string; }
interface XLabel { x: number; label: string; over: boolean; }

/**
 * SiteView budget burn-down — hand-rolled inline SVG. Cumulative planned vs
 * actual spend is drawn as an area (planned) + polyline (actual) across the
 * project phases; actual segments entering an over-budget phase render red.
 *
 * DATA CONTRACT: `lines` is a signal<BudgetLine[]> of mock data; the
 * service_agent stage clears it and wires ApiService.listBudget() per phase in
 * ngOnInit.
 */
@Component({
  selector: 'app-budget-burndown',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './budget-burndown.component.html',
  styleUrl: './budget-burndown.component.css',
})
export class BudgetBurndownComponent implements OnInit {
  readonly projectId = signal<string>('');

  readonly lines = signal<BudgetLine[]>([
    { id: 'b1', phaseId: 'ph1', phaseName: 'Site Prep & Foundation', plannedCents: 4200000, actualCents: 3980000 },
    { id: 'b2', phaseId: 'ph2', phaseName: 'Structure & Envelope', plannedCents: 8600000, actualCents: 9350000 },
    { id: 'b3', phaseId: 'ph3', phaseName: 'Interior & Fit-out', plannedCents: 5100000, actualCents: 2400000 },
  ]);

  // Logical SVG coordinate space (scales to container via width=100%).
  readonly vw = 660;
  readonly vh = 320;
  readonly padL = 64;
  readonly padR = 20;
  readonly padT = 20;
  readonly padB = 54;

  private get innerW() { return this.vw - this.padL - this.padR; }
  private get innerH() { return this.vh - this.padT - this.padB; }

  readonly rows = computed(() =>
    this.lines().map((l) => ({ ...l, over: l.actualCents > l.plannedCents })),
  );

  private cumulative(pick: (l: BudgetLine) => number): number[] {
    const out = [0];
    let sum = 0;
    for (const l of this.lines()) { sum += pick(l); out.push(sum); }
    return out;
  }

  readonly maxY = computed(() => {
    const p = this.cumulative((l) => l.plannedCents);
    const a = this.cumulative((l) => l.actualCents);
    return Math.max(...p, ...a, 1);
  });

  private xFor(i: number): number {
    const n = this.lines().length;
    return this.padL + (n === 0 ? 0 : (i / n) * this.innerW);
  }
  private yFor(v: number): number {
    return this.padT + this.innerH * (1 - v / this.maxY());
  }

  readonly plannedPts = computed<Pt[]>(() =>
    this.cumulative((l) => l.plannedCents).map((v, i) => ({ x: this.xFor(i), y: this.yFor(v) })),
  );
  readonly actualPts = computed<Pt[]>(() =>
    this.cumulative((l) => l.actualCents).map((v, i) => ({ x: this.xFor(i), y: this.yFor(v) })),
  );

  readonly plannedArea = computed(() => {
    const pts = this.plannedPts();
    if (pts.length === 0) return '';
    const baseY = this.yFor(0);
    const line = pts.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ');
    return `${line} L ${pts[pts.length - 1].x} ${baseY} L ${pts[0].x} ${baseY} Z`;
  });
  readonly plannedLine = computed(() =>
    this.plannedPts().map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' '),
  );

  readonly actualSegs = computed<Seg[]>(() => {
    const pts = this.actualPts();
    const rows = this.rows();
    const segs: Seg[] = [];
    for (let i = 1; i < pts.length; i++) {
      segs.push({ d: `M ${pts[i - 1].x} ${pts[i - 1].y} L ${pts[i].x} ${pts[i].y}`, over: rows[i - 1]?.over ?? false });
    }
    return segs;
  });

  readonly gridLines = computed<GridLine[]>(() => {
    const out: GridLine[] = [];
    const steps = 4;
    for (let i = 0; i <= steps; i++) {
      const v = (this.maxY() / steps) * i;
      out.push({ y: this.yFor(v), label: this.short(v) });
    }
    return out;
  });

  readonly xLabels = computed<XLabel[]>(() =>
    this.rows().map((l, i) => ({ x: this.xFor(i + 1), label: this.abbrev(l.phaseName ?? ''), over: l.over })),
  );

  readonly totalPlanned = computed(() => this.lines().reduce((s, l) => s + l.plannedCents, 0));
  readonly totalActual = computed(() => this.lines().reduce((s, l) => s + l.actualCents, 0));
  readonly overBudget = computed(() => this.totalActual() > this.totalPlanned());
  readonly actualEndY = computed(() => {
    const pts = this.actualPts();
    return pts[pts.length - 1]?.y ?? 0;
  });
  readonly actualEndX = computed(() => {
    const pts = this.actualPts();
    return pts[pts.length - 1]?.x ?? 0;
  });

  constructor(public auth: AuthService, private route: ActivatedRoute) {}

  ngOnInit(): void {
    this.route.parent?.paramMap.subscribe((p) => this.projectId.set(p.get('id') ?? ''));
  }

  dollars(cents: number): string {
    return (cents / 100).toLocaleString('en-US', { style: 'currency', currency: 'USD', maximumFractionDigits: 0 });
  }
  private short(cents: number): string {
    const d = cents / 100;
    return d >= 1000 ? `$${Math.round(d / 1000)}k` : `$${Math.round(d)}`;
  }
  private abbrev(name: string): string {
    return name.length > 16 ? name.slice(0, 15) + '…' : name;
  }
}
